import React, { useState, useRef } from 'react';
import EmojiPicker from 'emoji-picker-react';
import { useChat } from '../context/ChatContext';
import { useAuth } from '../context/AuthContext';
import { uploadMedia } from '../api';
import './MessageInput.css';

const MessageInput = () => {
  const [message, setMessage] = useState('');
  const [isUploading, setIsUploading] = useState(false);
  const [showEmojiPicker, setShowEmojiPicker] = useState(false);
  const { selectedUser, sendMessage, sendTyping, sendStopTyping } = useChat();
  const { user } = useAuth();
  const typingTimeout = useRef(null);
  const fileInputRef = useRef(null);

  const handleChange = (e) => {
    setMessage(e.target.value);

    if (selectedUser && user) {
      sendTyping(selectedUser._id, user._id);

      if (typingTimeout.current) {
        clearTimeout(typingTimeout.current);
      }

      typingTimeout.current = setTimeout(() => {
        sendStopTyping(selectedUser._id, user._id);
      }, 1000);
    }
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    if (!message.trim() || !selectedUser || !user) return;

    sendMessage(selectedUser._id, message.trim(), user._id);
    setMessage('');
    setShowEmojiPicker(false);
    sendStopTyping(selectedUser._id, user._id);
  };

  const handleEmojiClick = (emojiData) => {
    setMessage((prev) => prev + emojiData.emoji);
    setShowEmojiPicker(false);
  };

  const handlePickFile = () => {
    if (!selectedUser || isUploading) return;
    fileInputRef.current?.click();
  };

  const handleFileChange = async (e) => {
    const file = e.target.files?.[0];
    if (!file || !selectedUser || !user) return;

    setIsUploading(true);

    try {
      const response = await uploadMedia(file);

      sendMessage(selectedUser._id, {
        text: '',
        mediaUrl: response.url,
        mediaType: file.type
      }, user._id);
      sendStopTyping(selectedUser._id, user._id);
    } catch (error) {
      console.error('Upload error:', error);
      alert('Upload failed. Please try again.');
    } finally {
      setIsUploading(false);
      if (fileInputRef.current) {
        fileInputRef.current.value = '';
      }
    }
  };

  return (
    <form className="message-input" onSubmit={handleSubmit}>
      {showEmojiPicker && (
        <div className="emoji-picker-wrapper">
          <EmojiPicker onEmojiClick={handleEmojiClick} />
        </div>
      )}
      <button
        type="button"
        className="emoji-btn"
        onClick={() => setShowEmojiPicker(!showEmojiPicker)}
        disabled={!selectedUser}
        title="Add emoji"
      >
        😊
      </button>
      <button
        type="button"
        className="upload-btn"
        onClick={handlePickFile}
        disabled={!selectedUser || isUploading}
        title="Upload image or video"
      >
        📎
      </button>
      <input
        ref={fileInputRef}
        className="file-input"
        type="file"
        accept="image/*,video/*"
        onChange={handleFileChange}
      />
      <input
        type="text"
        value={message}
        onChange={handleChange}
        placeholder={isUploading ? 'Uploading...' : 'Type a message...'}
        disabled={!selectedUser || isUploading}
      />
      <button type="submit" disabled={!message.trim() || !selectedUser || isUploading}>
        {isUploading ? 'Wait' : 'Send'}
      </button>
    </form>
  );
};

export default MessageInput;
